1	//! `.lam` text emitter. Formats a compiled `Vec<Instr>` stream.
2	//!
3	//! Output discipline (docs/design.md §'.lam emitter output discipline'):
4	//! four-space indent for instructions; no trailing whitespace; atom
5	//! directives in order of first reference (same order compile.rs emits
6	//! them); labels follow the `pred_entry` / `pred_cK` / `pred_cK_body`
7	//! scheme. A blank line precedes each section-start label
8	//! (`*_body`, `*_entry`, `query`) and the initial `EXECUTE query`.
9	//!
10	//! Codegen.sno diverges from asm-spec.md in one respect: it emits a
11	//! fixed 10-atom preamble instead of an interned-in-order one. Per
12	//! plan.md §'Known risks', the Rust side follows the spec; the
13	//! golden fixture at tests/fixtures/ancestor.lam is the per-spec
14	//! reference.
15	
16	use crate::compile::{Instr, MAX_INSTR};
17	use crate::parse::{AtomId, AtomTable};
18	use crate::port::BoundedArr;
19	use core::fmt::Write;
20	use thiserror::Error;
21	
22	#[derive(Debug, Error, Clone, Copy, PartialEq, Eq)]
23	pub enum EmitError {
24	    #[error("unknown atom id in constant operand")]
25	    UnknownAtom,
26	    #[error("output buffer formatting error")]
27	    Fmt,
28	}
29	
30	pub fn emit(
31	    instrs: &BoundedArr<Instr, MAX_INSTR>,
32	    atoms: &AtomTable,
33	) -> Result<String, EmitError> {
34	    let mut out = String::with_capacity(1024);
35	    for i in 0..instrs.len() {
36	        let cur = instrs.get(i).expect("index in range");
37	        if needs_blank(i, instrs) {
38	            out.push('\n');
39	        }
40	        emit_one(cur, atoms, &mut out)?;
41	        out.push('\n');
42	    }
43	    Ok(out)
44	}
45	
46	fn needs_blank(i: usize, instrs: &BoundedArr<Instr, MAX_INSTR>) -> bool {
47	    if i == 0 {
48	        return false;
49	    }
50	    let prev = instrs.get(i - 1).expect("prev in range");
51	    let cur = instrs.get(i).expect("cur in range");
52	    if matches!(prev, Instr::AtomDir { .. }) && !matches!(cur, Instr::AtomDir { .. }) {
53	        return true;
54	    }
55	    if let Instr::Label(l) = cur {
56	        return is_section_label(l.as_str());
57	    }
58	    false
59	}
60	
61	fn is_section_label(name: &str) -> bool {
62	    name == "query" || name.ends_with("_entry") || name.ends_with("_body")
63	}
64	
65	fn emit_one(instr: &Instr, atoms: &AtomTable, out: &mut String) -> Result<(), EmitError> {
66	    match instr {
67	        Instr::AtomDir { id, name } => {
68	            wf(out, format_args!(".atom {} {}", id, name.as_str()))
69	        }
70	        Instr::Label(l) => wf(out, format_args!("{}:", l.as_str())),
71	        _ => emit_instr(instr, atoms, out),
72	    }
73	}
74	
75	fn emit_instr(instr: &Instr, atoms: &AtomTable, out: &mut String) -> Result<(), EmitError> {
76	    match instr {
77	        Instr::PutConst { ai, atom } => emit_put_const(*ai, *atom, atoms, out),
78	        Instr::PutVar { ai, xi } => wf(out, format_args!("    PUT_VAR X{xi}, A{ai}")),
79	        Instr::PutVal { ai, xi } => wf(out, format_args!("    PUT_VAL X{xi}, A{ai}")),
80	        Instr::PutYVal { ai, yi } => wf(out, format_args!("    PUT_Y_VAL Y{yi}, A{ai}")),
81	        Instr::GetVar { ai, xi } => wf(out, format_args!("    GET_VAR X{xi}, A{ai}")),
82	        Instr::GetYVar { ai, yi } => wf(out, format_args!("    GET_Y_VAR Y{yi}, A{ai}")),
83	        Instr::GetConst { ai, atom } => emit_get_const(*ai, *atom, atoms, out),
84	        Instr::GetStruct { ai, atom, arity } => emit_get_struct(*ai, *atom, *arity, atoms, out),
85	        Instr::UnifyVar { xi } => wf(out, format_args!("    UNIFY_VAR X{xi}")),
86	        Instr::UnifyVal { xi } => wf(out, format_args!("    UNIFY_VAL X{xi}")),
87	        Instr::Allocate { n } => wf(out, format_args!("    ALLOCATE {n}")),
88	        Instr::Deallocate => ps(out, "    DEALLOCATE"),
89	        Instr::Call { label } => wf(out, format_args!("    CALL {}", label.as_str())),
90	        Instr::Execute { label } => wf(out, format_args!("    EXECUTE {}", label.as_str())),
91	        Instr::Proceed => ps(out, "    PROCEED"),
92	        Instr::Try { label } => wf(out, format_args!("    TRY {}", label.as_str())),
93	        Instr::Retry { label } => wf(out, format_args!("    RETRY {}", label.as_str())),
94	        Instr::Trust { .. } => ps(out, "    TRUST"),
95	        Instr::Cut => ps(out, "    CUT"),
96	        Instr::Fail => ps(out, "    FAIL"),
97	        Instr::BWrite { ai } => wf(out, format_args!("    B_WRITE A{ai}")),
98	        Instr::BNl => ps(out, "    B_NL"),
99	        Instr::BIsAdd { .. } => ps(out, "    B_IS_ADD"),
100	        Instr::BIsSub { .. } => ps(out, "    B_IS_SUB"),
101	        Instr::BLt { .. } => ps(out, "    B_LT"),
102	        Instr::BGt { .. } => ps(out, "    B_GT"),
103	        Instr::Halt => ps(out, "    HALT"),
104	        Instr::AtomDir { .. } | Instr::Label(_) => Ok(()),
105	    }
106	}
107	
108	fn emit_put_const(ai: u8, atom: AtomId, atoms: &AtomTable, out: &mut String) -> Result<(), EmitError> {
109	    let n = atom_name(atoms, atom)?;
110	    wf(out, format_args!("    PUT_CONST A{ai}, atom({n})"))
111	}
112	
113	fn emit_get_const(ai: u8, atom: AtomId, atoms: &AtomTable, out: &mut String) -> Result<(), EmitError> {
114	    let n = atom_name(atoms, atom)?;
115	    wf(out, format_args!("    GET_CONST A{ai}, atom({n})"))
116	}
117	
118	fn emit_get_struct(
119	    ai: u8,
120	    atom: AtomId,
121	    arity: u8,
122	    atoms: &AtomTable,
123	    out: &mut String,
124	) -> Result<(), EmitError> {
125	    let n = atom_name(atoms, atom)?;
126	    wf(out, format_args!("    GET_STRUCT A{ai}, {n}/{arity}"))
127	}
128	
129	fn atom_name(atoms: &AtomTable, id: AtomId) -> Result<&str, EmitError> {
130	    atoms.name(id).map(|n| n.as_str()).ok_or(EmitError::UnknownAtom)
131	}
132	
133	fn wf(out: &mut String, args: core::fmt::Arguments<'_>) -> Result<(), EmitError> {
134	    out.write_fmt(args).map_err(|_| EmitError::Fmt)
135	}
136	
137	fn ps(out: &mut String, s: &str) -> Result<(), EmitError> {
138	    out.push_str(s);
139	    Ok(())
140	}
